class Solution {
public:
    int numWays(int steps, int arrLen) {
        const int MOD = 1e9 + 7;
        arrLen = min(arrLen, steps + 1);
        vector<int> dp(arrLen, 0);
        dp[0] = 1;
        for (int i = 1; i <= steps; ++i) {
            vector<int> next_dp(arrLen, 0);
            for (int j = 0; j < arrLen; ++j) {
                next_dp[j] = dp[j];
                if (j > 0) next_dp[j] = (next_dp[j] + dp[j - 1]) % MOD;
                if (j < arrLen - 1) next_dp[j] = (next_dp[j] + dp[j + 1]) % MOD;
            }
            dp = next_dp;
        }
        return dp[0];
    }
};
```
efficiency: HIGH
time complexity: O(steps * min(arrLen, steps))
space complexity: O(min(arrLen, steps))
